from flask import Flask, request, render_template
from html.parser import HTMLParser
import re

app = Flask(__name__)

class BoldItalicHTMLParser(HTMLParser):
    def handle_starttag(self, tag, attrs):
        if tag.lower() == 'b':
            self.bold = True
        elif tag.lower() == 'i':
            self.italic = True

    def handle_endtag(self, tag, attrs):
        if tag.lower() == 'b':
            self.bold = False
        elif tag.lower() == 'i':
            self.italic = False

    def handle_data(self, data):
        if self.bold:
            data = "<b>" + data + "</b>"
        if self.italic:
            data = "<i>" + data + "</i>"
        self.result += data

class User:
    def __init__(self, name, bio, location, status):
        self.name = name
        self.bio = bio
        self.location = location
        self.status = status

